   983→	ctx context.Context, typ reflect.Type, defaultVal reflect.Value, node ast.Node,
   984→) (reflect.Value, error) {
   985→	if node.Type() == ast.AliasType {
   986→		aliasName := node.(*ast.AliasNode).Value.GetToken().Value
   987→		newValue := d.anchorValueMap[aliasName]
   988→		if newValue.IsValid() {
   989→			return newValue, nil
   990→		}
   991→	}
   992→	if node.Type() == ast.NullType {
   993→		return reflect.Zero(typ), nil
   994→	}
   995→	newValue := d.createDecodableValue(typ)
   996→	for defaultVal.Kind() == reflect.Ptr {
   997→		defaultVal = defaultVal.Elem()
   998→	}
   999→	if defaultVal.IsValid() && defaultVal.Type().AssignableTo(newValue.Type()) {
  1000→		newValue.Set(defaultVal)
  1001→	}
  1002→	if err := d.decodeValue(ctx, newValue, node); err != nil {
  1003→		return newValue, errors.Wrapf(err, "failed to decode value")
  1004→	}
  1005→	return newValue, nil
  1006→}
