func (c *unmarshalContext) UnmarshalYAML(ctx context.Context, b []byte) error {
	v, ok := ctx.Value("k").(int)
	if !ok {
		return fmt.Errorf("cannot get valid context")
	}
	if v != 1 {
		return fmt.Errorf("cannot get valid context")
	}
	if string(b) != "1" {
		return fmt.Errorf("cannot get valid bytes")
	}
	c.v = v
	return nil
}

